export default function Navbar({ setPage, user, onLogout, onBack, showBack }) {
  return (
    <nav className="top-nav" style={{ 
      background: "rgba(255, 255, 255, 0.8)", 
      backdropFilter: "blur(12px)",
      borderBottom: "1px solid var(--border-light)",
      display: "flex", 
      alignItems: "center", 
      justifyContent: "space-between", 
      padding: "0 40px", 
      height: "64px", 
      position: "sticky", 
      top: 0, 
      zIndex: 1000 
    }}>
      <div style={{ display: "flex", alignItems: "center", gap: "24px" }}>
        {showBack && (
          <button className="btn-back" onClick={onBack}>
            <span style={{ fontSize: "18px" }}>←</span> Back
          </button>
        )}
        <button 
          className="top-nav-logo" 
          onClick={() => setPage("home")}
          style={{ background: "none", border: "none", display: "flex", alignItems: "center", gap: "10px", color: "var(--navy)", fontSize: "20px", fontWeight: "700", fontFamily: "'Playfair Display', serif" }}
        >
          <div style={{ width: "30px", height: "30px", background: "linear-gradient(135deg, var(--primary), #c0392b)", borderRadius: "8px", display: "flex", alignItems: "center", justifyContent: "center", color: "#fff", fontSize: "16px" }}>🍽</div>
          RecipeNest
        </button>
      </div>

      <div className="top-nav-links" style={{ display: "flex", gap: "10px" }}>
        <button className="top-nav-link" onClick={() => setPage("home")}>Discover</button>
        <button className="top-nav-link">Categories</button>
        <button className="top-nav-link">Chefs</button>
      </div>

      <div className="top-nav-actions" style={{ display: "flex", alignItems: "center", gap: "12px" }}>
        {user ? (
          <>
            <div style={{ display: "flex", alignItems: "center", gap: "10px", padding: "4px 12px", background: "#f1f5f9", borderRadius: "99px" }}>
              <div style={{ width: "24px", height: "24px", borderRadius: "50%", background: "var(--primary)", color: "#fff", fontSize: "10px", display: "flex", alignItems: "center", justifyContent: "center", fontWeight: "700" }}>
                {user.name.split(' ').map(n => n[0]).join('')}
              </div>
              <span style={{ fontSize: "13px", fontWeight: "600", color: "var(--text-main)" }}>{user.name}</span>
            </div>
            <button className="top-nav-link" onClick={() => {
              if (user.role === "user") setPage("user-dashboard");
              else if (user.role === "chef") setPage("chef-dashboard");
              else if (user.role === "admin") setPage("admin-dashboard");
            }}>
              Dashboard
            </button>
            <button className="top-nav-cta" style={{ background: "#f1f5f9", color: "var(--text-main)", border: "1px solid #e2e8f0" }} onClick={onLogout}>Logout</button>
          </>
        ) : (
          <>
            <button className="top-nav-link" onClick={() => setPage("login")}>Sign In</button>
            <button className="btn-primary" style={{ padding: "8px 20px", fontSize: "13px" }} onClick={() => setPage("signup")}>Get Started</button>
          </>
        )}
      </div>
    </nav>
  );
}
